import{_ as o,c as d,o as t,ae as a}from"./chunks/framework.CLNW5JS9.js";const p=JSON.parse('{"title":"通道档案树（G6 TreeGraph）问题记录与修复说明","description":"","frontmatter":{},"headers":[],"relativePath":"vue/antv-g6-error.md","filePath":"vue/antv-g6-error.md"}'),c={name:"vue/antv-g6-error.md"};function l(r,e,n,s,i,h){return t(),d("div",null,e[0]||(e[0]=[a('<h1 id="通道档案树-g6-treegraph-问题记录与修复说明" tabindex="-1">通道档案树（G6 TreeGraph）问题记录与修复说明 <a class="header-anchor" href="#通道档案树-g6-treegraph-问题记录与修复说明" aria-label="Permalink to &quot;通道档案树（G6 TreeGraph）问题记录与修复说明&quot;">​</a></h1><p>本文档梳理「懒加载子节点先出现后又被父节点收起」等问题的排查过程与最终方案，对应实现文件：<code>ggTree.vue</code>。</p><hr><h2 id="_1-问题现象" tabindex="-1">1. 问题现象 <a class="header-anchor" href="#_1-问题现象" aria-label="Permalink to &quot;1. 问题现象&quot;">​</a></h2><ul><li><strong>现象 A</strong>：点击需要懒加载的节点后，子节点会先渲染出来，随后整棵子树又被收起来，视觉上像「闪一下又折叠」。</li><li><strong>现象 B（曾讨论）</strong>：生产环境使用 HTTPS 是否会导致上述现象。</li></ul><hr><h2 id="_2-技术背景" tabindex="-1">2. 技术背景 <a class="header-anchor" href="#_2-技术背景" aria-label="Permalink to &quot;2. 技术背景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>说明</th></tr></thead><tbody><tr><td>图类型</td><td><code>G6.TreeGraph</code>（<code>@antv/g6</code> 4.8.x，实际由 <code>@antv/g6-pc</code> 提供行为与插件）</td></tr><tr><td>交互</td><td><code>modes.default</code> 中配置了 <code>collapse-expand</code>，以及自定义 <code>node:click</code> 做接口懒加载</td></tr><tr><td>懒加载</td><td>点击节点后请求 <code>getTagRegionCount</code> / <code>getChannelByPage</code>，再 <code>changeData</code>、<code>layout</code> 等更新树</td></tr></tbody></table><hr><h2 id="_3-排查过程-按时间线" tabindex="-1">3. 排查过程（按时间线） <a class="header-anchor" href="#_3-排查过程-按时间线" aria-label="Permalink to &quot;3. 排查过程（按时间线）&quot;">​</a></h2><h3 id="_3-1-初步猜测-https-影响" tabindex="-1">3.1 初步猜测：HTTPS 影响 <a class="header-anchor" href="#_3-1-初步猜测-https-影响" aria-label="Permalink to &quot;3.1 初步猜测：HTTPS 影响&quot;">​</a></h3><ul><li><strong>结论</strong>：HTTPS <strong>通常不会</strong>直接导致「先展开再收起」这种纯前端交互顺序问题。</li><li><strong>例外</strong>：若页面是 <code>https</code>，而接口被配置成明文 <code>http</code> 且非同源代理，浏览器可能拦截混合内容（Mixed Content），请求失败会导致子节点不出现或逻辑异常；但与本问题描述的「已出现再收起」不完全一致。</li><li>本项目业务请求多通过 <code>axios</code> + <code>process.env.VUE_APP_BASE_API</code>（相对同源或统一网关），与 G6 画布折叠无直接耦合；<code>public/ip-config.js</code> 中的 <code>window.httpType</code> 主要用于 WebSocket/登录等参数，与树懒加载 axios 路径无必然关系。</li></ul><h3 id="_3-2-第一次尝试-在-collapse-expand-的-onchange-里-return-false" tabindex="-1">3.2 第一次尝试：在 <code>collapse-expand</code> 的 <code>onChange</code> 里 <code>return false</code> <a class="header-anchor" href="#_3-2-第一次尝试-在-collapse-expand-的-onchange-里-return-false" aria-label="Permalink to &quot;3.2 第一次尝试：在 `collapse-expand` 的 `onChange` 里 `return false`&quot;">​</a></h3><ul><li><strong>设想</strong>：通过 <code>onChange</code> 阻止折叠状态写入。</li><li><strong>结果</strong>：<strong>无效</strong>。</li><li><strong>原因</strong>：需对照 G6 4.8 源码（<code>node_modules/@antv/g6-pc/lib/behavior/collapse-expand.js</code>）： <ul><li><code>trigger === &#39;click&#39;</code> 时，<code>onNodeClick</code> 内部使用 <strong><code>setTimeout(..., 200)</code></strong> 延迟执行 <code>toggle</code>。</li><li><code>toggle</code> 中<strong>先</strong>根据源数据计算 <code>collapsed = !sourceData.collapsed</code>，<strong>直接写入</strong> <code>sourceData.collapsed</code> 与 <code>item.getModel().collapsed</code>，再 <code>emit(&#39;itemcollapsed&#39;)</code>，然后才调用 <code>onChange</code>，最后<strong>无条件</strong>执行 <code>this.graph.layout()</code>。</li><li>因此：<code>onChange</code> 的返回值<strong>不能</strong>阻止前面已写入的 <code>collapsed</code>，也<strong>不能</strong>阻止最后的 <code>layout()</code>；与「在 onChange 里拦截」的预期不符。</li></ul></li></ul><h3 id="_3-3-根因归纳" tabindex="-1">3.3 根因归纳 <a class="header-anchor" href="#_3-3-根因归纳" aria-label="Permalink to &quot;3.3 根因归纳&quot;">​</a></h3><ol><li><strong>时序冲突</strong>：懒加载是异步的；接口返回后子节点已挂上并布局，约 <strong>200ms</strong> 后 <code>collapse-expand</code> 的延迟 <code>toggle</code> 才执行，把父节点当成「用户再次点击要折叠」处理，触发 <code>layout</code>，子树被收起。</li><li><strong>误判修复点</strong>：问题不在 HTTPS，而在 <strong>G6 <code>collapse-expand</code> 的 200ms 防抖/延迟</strong> 与 <strong>异步懒加载</strong> 叠加。</li></ol><hr><h2 id="_4-最终方案-已实现" tabindex="-1">4. 最终方案（已实现） <a class="header-anchor" href="#_4-最终方案-已实现" aria-label="Permalink to &quot;4. 最终方案（已实现）&quot;">​</a></h2><h3 id="_4-1-使用-shouldbegin-在折叠逻辑入口拦截" tabindex="-1">4.1 使用 <code>shouldBegin</code> 在折叠逻辑入口拦截 <a class="header-anchor" href="#_4-1-使用-shouldbegin-在折叠逻辑入口拦截" aria-label="Permalink to &quot;4.1 使用 `shouldBegin` 在折叠逻辑入口拦截&quot;">​</a></h3><p><code>collapse-expand</code> 在 <code>toggle</code> 开头会调用 <code>shouldBegin(e, collapsed, this)</code>，若返回 <code>false</code>，则<strong>不会</strong>修改 <code>collapsed</code>、也不会继续 <code>layout</code>。</p><p>在 <code>ggTree.vue</code> 中为 <code>collapse-expand</code> 配置：</p><ul><li><strong><code>shouldBegin</code></strong>： <ul><li>若节点带有 <strong><code>_lazyExpandLocked</code></strong>（短期锁），强制 <code>collapsed = false</code> 并 <code>return false</code>，避免延迟 200ms 的那次折叠生效。</li><li>若为懒加载节点（<code>hasChildren &amp;&amp; !loaded</code>）且仍在加载或尚无子数据（<code>loading</code> 或 <code>children</code> 为空），同样 <code>return false</code>，避免与懒加载展开冲突。</li></ul></li><li><strong><code>onChange</code></strong>：仅同步 <code>item.getModel().collapsed</code> 与行为传入的 <code>collapsed</code>（在允许折叠时保持一致）。</li></ul><h3 id="_4-2-懒加载点击时加短期锁" tabindex="-1">4.2 懒加载点击时加短期锁 <a class="header-anchor" href="#_4-2-懒加载点击时加短期锁" aria-label="Permalink to &quot;4.2 懒加载点击时加短期锁&quot;">​</a></h3><p>在 <code>node:click</code> 里，在发起请求前：</p><ul><li><code>model.loading = true</code></li><li><code>model._lazyExpandLocked = true</code></li><li>使用 <code>model._lazyExpandTs</code> 记录本次锁的时间戳，<code>setTimeout(..., 260)</code> 后仅当时间戳仍匹配时解锁，避免与 <code>collapse-expand</code> 的 <strong>200ms</strong> 延迟撞车，并减少快速连点导致锁状态错乱。</li></ul><h3 id="_4-3-与生产环境的关系" tabindex="-1">4.3 与生产环境的关系 <a class="header-anchor" href="#_4-3-与生产环境的关系" aria-label="Permalink to &quot;4.3 与生产环境的关系&quot;">​</a></h3><ul><li>部署为 HTTPS 后，只要重新构建并带上上述前端逻辑，<strong>不需要</strong>为「收起闪烁」单独改协议。</li><li>若懒加载接口在生产失败，应查 Network 面板（4xx/5xx、混合内容、CORS），属于另一类问题。</li></ul><hr><h2 id="_5-相关代码位置-便于维护" tabindex="-1">5. 相关代码位置（便于维护） <a class="header-anchor" href="#_5-相关代码位置-便于维护" aria-label="Permalink to &quot;5. 相关代码位置（便于维护）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>文件与位置</th></tr></thead><tbody><tr><td><code>collapse-expand</code> 的 <code>shouldBegin</code> / <code>onChange</code></td><td><code>ggTree.vue</code> → <code>modes.default</code> 内</td></tr><tr><td>懒加载锁 <code>_lazyExpandLocked</code></td><td><code>ggTree.vue</code> → <code>graph.on(&#39;node:click&#39;, ...)</code> 内</td></tr><tr><td>G6 4.8 行为源码参考</td><td><code>node_modules/@antv/g6-pc/lib/behavior/collapse-expand.js</code></td></tr></tbody></table><hr><h2 id="_6-附录-小地图-minimap-与文档版本" tabindex="-1">6. 附录：小地图（Minimap）与文档版本 <a class="header-anchor" href="#_6-附录-小地图-minimap-与文档版本" aria-label="Permalink to &quot;6. 附录：小地图（Minimap）与文档版本&quot;">​</a></h2><ul><li>官方文档 <a href="https://g6.antv.antgroup.com/manual/plugin/minimap" target="_blank" rel="noreferrer">Minimap 插件</a> 面向 <strong>G6 5.x</strong>，配置形如 <code>plugins: [{ type: &#39;minimap&#39;, ... }]</code>。</li><li>本项目为 <strong>G6 4.8.x</strong>，应使用 <strong><code>new G6.Minimap({ ... })</code></strong> 作为插件实例传入 <code>plugins</code>，并在样式中通过 <code>#treeGraph .g6-minimap</code> 等做定位与外观（详见 <code>ggTree.vue</code>）。</li></ul><hr><h2 id="_7-小结" tabindex="-1">7. 小结 <a class="header-anchor" href="#_7-小结" aria-label="Permalink to &quot;7. 小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>根因</th><th>修复要点</th></tr></thead><tbody><tr><td>懒加载后子节点先出现后收起</td><td><code>collapse-expand</code> 在 click 下 <strong>200ms 延迟 toggle</strong>，与异步懒加载时序冲突</td><td>用 <strong><code>shouldBegin</code> + <code>_lazyExpandLocked</code></strong> 在写入 <code>collapsed</code> 之前拦截</td></tr><tr><td>HTTPS 是否主因</td><td>否（除非接口被拦导致请求失败）</td><td>区分网络错误与 G6 行为时序</td></tr></tbody></table>',36)]))}const u=o(c,[["render",l]]);export{p as __pageData,u as default};
